var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"일주일 전","JPN":"一週間前","ENG":"One week ago","TWN":"一周前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 ~ 로터스 관리 경계 구역","JPN":"シャレード～ロータス管理警戒区域","ENG":"Charade-Lotus Perimeter Zone","TWN":"查雷德 ~ 洛德斯管理警戒區域"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"매스헤르츠 채널에서 전해드리는 속보입니다.","JPN":"マスヘルツチャンネルからの速報です。","ENG":"This is a breaking news report from the Masshertz channel.","TWN":"以下是來自梅斯赫茲頻道的快訊。"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"현재 샤레이드, 로터스 관리 경계 구역 인근에서 정체불명의 우주선이 출몰했습니다.","JPN":"ただいまシャレード、ロータス管理警戒区域付近に正体不明の宇宙船が現れました。","ENG":"A mysterious spaceship has appeared near the Charade-Lotus perimeter zone.","TWN":"目前在查雷德和洛德斯管理的警戒區域附近出現了不明身份的太空船。"},"stage":{"bg":"HELI_NORMAL","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"추정 직경 3km의 거대한 우주선은 관리 경계 구역 상공을 부유하고 있습니다만…….","JPN":"推定直径3kmの巨大な宇宙船は、管理警戒区域の上空を浮遊していますが……","ENG":"A massive spaceship, estimated at 3 kilometers across, is now hovering above the perimeter zone...","TWN":"推測直徑3公里的巨大宇宙船正在管理邊界區域上空漂浮……"},"stage":{"bg":"MS_1407","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"현재로서는 어떠한 움직임을 보이지 않고 있는데요…….","JPN":"現在としては、これといった動きは見せていません……","ENG":"But so far, it has shown no signs of movement...","TWN":"目前沒有任何動靜……"},"stage":{"bg":"MS_1407","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color>","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>","ENG":"Administration Direct Control City, <color=#ffd34c>Charade</color>","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>"},"stage":{"bg":"BLACK","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"관리국에 따르면, 당국은 우주선의 출몰에 대해 인지하고 있으며, 조사를 진행 중이나…….","JPN":"管理局によると、当局は宇宙船の出現について認知しており、調査を進めてはいますが……","ENG":"According to the Administration, authorities are aware of the spaceship's presence and have begun an investigation...","TWN":"根據管理局的說法，當局已經注意到飛船的出現，並正在進行調查……"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"아직 구체적인 답변은 내놓지 않은 상황입니다. 이에 따라…….","JPN":"未だ具体的な解答は出されていない状況です。これにより……","ENG":"However, no official explanation has been provided at this time. As a result...","TWN":"目前還沒有給出具體的答覆。因此……"},"stage":{"bg":"CITY_CENTER1","bgm":"UI_CONSORTIUM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 갑자기 멍하니 서서 왜 그래요?","JPN":"ライカ、急にぼーっとしてどうしたの？","ENG":"Laika, why are you just standing there like that?","TWN":"萊卡，怎麼突然呆呆地站著？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우윽……!","JPN":"ううっ……！","ENG":"Ugh...!","TWN":"唔呃……！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_03"},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라, 라이카…! 괜찮아요……!?","JPN":"ら、ライカ……！　大丈夫……！？","ENG":"L-Laika...! Are you all right...?!","TWN":"萊，萊卡……！你沒事吧……！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_05"},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"식은땀 좀 봐! 안색이 새파랗잖아요!","JPN":"冷汗がすごい！　顔に血の気がないじゃない！","ENG":"You're drenched in cold sweat! And your face is pale!","TWN":"看看你這冷汗！臉色都發青了！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"허억, 허억, 허억……!!","JPN":"はあ、はあ、はあ……！！","ENG":"*Huff!* *Huff!* *Huff…!*","TWN":"呵，呵，呵……！！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저거야…….","JPN":"あれだ……","ENG":"That's it...","TWN":"那個……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"네? 갑자기 무슨 소리예요?","JPN":"え？　いきなり何のこと？","ENG":"Huh? What are you talking about all of a sudden?","TWN":"是？你幹嘛突然說這種話？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저거라고……!","JPN":"あれなんだ……！","ENG":"That's it...!","TWN":"那是……！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>목표 지점에서 나타나는 현상을 관측, 연구하라.</color>","JPN":"<color=#ffd34c>目標地点における現象を観測、研究せよ。</color>","ENG":"<color=#ffd34c>Observe the phenomenon at the objective point, and research it.</color>","TWN":"<color=#ffd34c>觀察並研究在目標地點出現的現象。</color>"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"탐사단 대부분이 개죽음당하면서… 간신히 도착했던 목표 지점…….","JPN":"探査チームのほとんどが無意味に命を落としながら……やっとの思いで到達した目標地点……","ENG":"After most of the expedition team died horribly, we barely made it to the target site...","TWN":"探索隊的大部分人都白白喪命……明明好不容易才到達了目標地點……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"거기서… 우리가 본 게 <color=#ffd34c>저거</color>야…….","JPN":"そこで……私たちが見たのが、<color=#ffd34c>アレ</color>だ……","ENG":"<color=#ffd34c>That</color> is what we saw there...","TWN":"而我們在那裡看到的就是<color=#ffd34c>那個</color>……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그, 그렇다면…….","JPN":"じゃ、じゃあ……","ENG":"Th-then...","TWN":"那、那樣的話……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"설마, 라이카가 우주에서 봤다고 했던 게 저 우주선이라고요……?","JPN":"まさか、ライカが宇宙で見たって言っていたのが、あの宇宙船なの……？","ENG":"Are you saying that spaceship is what Laika saw in space back then?","TWN":"難道，萊卡在太空中看到的就是那艘太空船嗎……？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……그래.","JPN":"……そうさ。","ENG":"...Yes.","TWN":"……是啊。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"달의 뒷면을 새까맣게 뒤덮은 무수한 <color=#ffd34c>우주 함대</color>들…….","JPN":"月の裏側を真っ黒に覆う、無数の<color=#ffd34c>宇宙艦隊</color>……","ENG":"Countless <color=#ffd34c>space fleets</color>, blanketing the dark side of the moon in total darkness...","TWN":"無數漆黑覆蓋月球背面的<color=#ffd34c>宇宙艦隊</color>……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그리고 저건… 모든 함대를 통솔하고 있던 <color=#ffd34c>마더 쉽</color>이야…….","JPN":"そしてあれは……その全ての艦隊を統率していた<color=#ffd34c>マザーシップ</color>だ……","ENG":"And that... that's the <color=#ffd34c>mothership</color>. The one that commanded the entire fleet...","TWN":"而那是……統率所有艦隊的<color=#ffd34c>母艦</color>……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하지만 어째서… 마더 쉽이……?","JPN":"でも、どうして……マザーシップが……？","ENG":"But... why is the mothership here...?","TWN":"但是為什麼……母艦會……？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 재건 도시 <color=#ffd34c>ARC-NL1</color>\\n구 네덜란드, 암스테르담","JPN":"管理局再建都市<color=#ffd34c>ARC-NL1</color>\\n旧オランダ、アムステルダム","ENG":"Administration Rebuilt City <color=#ffd34c>ARC-NL1</color>\\nAmsterdam, Old Netherlands","TWN":"管理局重建城市<color=#ffd34c>ARC-NL1</color>\\n舊荷蘭，阿姆斯特丹"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"subtitle","speaker":null,"text":{"KOREA":"다국적 합자 대침식 연구소 – 퓨처 앳 워\\n<color=#ffd34c>제3지부 항공 우주 연구소</color>","JPN":"多国籍合資対侵食戦研究所 - フューチャーアットウォー\\n<color=#ffd34c>第3支部航空宇宙研究所</color>","ENG":"Multinational Anti-Corruption Research Lab - Future-at-War\\n<color=#ffd34c>Aerospace Research Lab, Branch 3</color>","TWN":"跨國合資反侵蝕研究所-天啟兵器\\n<color=#ffd34c>第三分部航空宇宙研究所</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"얼마 전에 있었던 최고등급 재난경보에 이어, 이번 우주선 출몰로 시민들은 불안에 떨고 있는데요.","JPN":"この間の最高ランクの災難警報に続く今回の宇宙船の出現で、市民たちは不安に怯えています。","ENG":"Following the recent highest-level disaster alert, the sudden appearance of a spaceship has left citizens on edge.","TWN":"繼前不久的最高等級災難警報之後，這次的飛船出沒讓市民們感到不安。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L50_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"일각에서는 이 우주선이 외계인과의 접촉이나, 북방합의체의 신형병기라는 음모론도…….","JPN":"一角ではこの宇宙船がエイリアンとの接触や、北方合意体の新型兵器だという陰謀論も……","ENG":"Some speculate that it may signal alien contact or perhaps a secret new weapon developed by the Northern Union...","TWN":"有些人抱持陰謀論觀點，認為這艘太空船與外星人接觸了，亦或者是北方和議會的新型武器……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_QM","text":{"KOREA":"……의체 점검 끝났어, 망할 깡통.","JPN":"……義体のメンテナンス終わったわ、ポンコツのボロ缶。","ENG":"...System check's done, Tin Can.","TWN":"……義肢檢查完畢，該死的鐵桶。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_QM","text":{"KOREA":"클리포트 게임 동안, 그 몸으로 무슨 짓을 하고 다녔는지는 모르겠지만… 좀 아껴 쓰지 그래?","JPN":"クリフォトゲームの間、その身体で何をしていたのかは知らないけど……すこしは大切にしたらどう？","ENG":"I don't know what you were doing with that body of yours during the Qliphoth Game, but maybe try taking better care of it?","TWN":"逆卡巴拉遊戲期間，不知道你用那身體做了什麼……能不能節省點用？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_QM","text":{"KOREA":"그 인간형 소체가 얼마나 델리케이트한 녀석인지 알기나 해?","JPN":"あんた、その人間型ボディーがどんだけデリケートなのかわかってる？","ENG":"Do you have any idea how fragile that humanoid body is?","TWN":"你知道那個類人型軀體有多麼精密嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_QM","text":{"KOREA":"돈으로 환산하면, 천문학적인 금액이라고.","JPN":"お金に換算したら、天文学的な額なんだけど。","ENG":"In raw value? We're talking astronomical.","TWN":"換算成錢的話，是天文數字的金額。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"물론이라네, 닥터 메이시.","JPN":"もちろんさ、ドクター・メイシ。","ENG":"Naturally, Doctor Macy.","TWN":"那當然，梅西博士。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그렇기에 다른 이가 아닌, 바로 자네에게 이 몸을 맡기는 것 아닌가.","JPN":"だからこそ他の誰でもない、君にこの身体を任せている。","ENG":"That's precisely why I entrust this body to you and no one else.","TWN":"正因為如此，我才將自己託付給你，而不是別人。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"이 소체를 직접 제작한 당사자에게 말이야.","JPN":"このボディーを制作した当人にね。","ENG":"To the very person who actually built this body.","TWN":"去對直接製作這個軀體的當事人說吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"시끄러워.","JPN":"うるさいわ。","ENG":"Oh, shut up.","TWN":"吵死了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"인간도 아닌 주제에 인간인 척, 수작 부리지 말아줄래?","JPN":"人間でもないくせに、人間みたいなこと言わないでくれる？","ENG":"Quit pretending to be human when you're clearly not.","TWN":"明明不是人類，卻裝成人類，能不能別耍花招？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"후후, 기분이 상했다면 사과하겠네. 닥터.","JPN":"ふふ、気に障ったのなら謝るよ、ドクター。","ENG":"Haha. My apologies if I offended you, Doctor.","TWN":"呵呵，如果讓你不愉快的話，我願意道歉，博士。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"하지만 자네도 알고 있을 텐데.","JPN":"しかし君もわかっているだろう？","ENG":"But surely, you must be aware of it.","TWN":"但你也應該知道。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"자네가 현재 몸 담고 있는, 이 퓨처 앳 워 연구 재단의 실질적인 의사 결정자가 누구인지.","JPN":"君が現在身を置いている、このフューチャーアットウォー研究財団の実質的な意思決定者が誰なのか。","ENG":"Who really holds authority at the Future-at-War research foundation?","TWN":"你現在所在的這個天啟兵器研究基金會的實際決策者是誰。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그리고 로스트쉽 시무르그의 수색과 인양 작업을 도와준 게 누구인지를 말이야.","JPN":"そしてロストシップ・シムルグの捜索や引き揚げ作業に手を貸したのが誰なのかを。","ENG":"And who was behind the recovery of the Lost Ship, Simurgh?","TWN":"還有誰幫忙搜尋和打撈了失落之船西姆爾格。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"아이고~!","JPN":"いや～！","ENG":"Oh, of course!","TWN":"哎呀～"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그거야 모두 잘나 빠진 우리 의장 나리 덕분 아니겠습니까요~!","JPN":"そりゃもう全部、偉くて偉い議長様のおかげでやんすよ～！","ENG":"Why, it's all thanks to our glorious chairman, isn't it?","TWN":"那還不是多虧了我們那位了不起的議長大人～"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"……이럴 줄 알았어?","JPN":"……とでも言うと思った？","ENG":"...Did you expect me to say something like this?","TWN":"……我就知道會這樣？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그것조차 다 나를 평의회로 끌어들이기 위한 안배였다고 주장할 셈이지?","JPN":"それすらも私を評議会に引き入れるための根回しだったと主張するんでしょ？","ENG":"So that was all just a setup to rope me into the Council, huh?","TWN":"你是想說那也是為了把我拉進評議會的安排嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그래서? 내가 널 돕지 않겠다면 어쩔 건데?","JPN":"それで？　私があんたに協力しないと言ったら、どうする気？","ENG":"What if I refuse to help you? Then what?","TWN":"然後呢？如果我不幫你，你會怎麼樣？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"닥터, 나는 이미 자네의 대답을 알고 있네.","JPN":"ドクター、私はすでに君がなんと答えるかわかっているんだ。","ENG":"Doctor, I already know what your answer will be.","TWN":"博士，我已經知道你的答案了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"우씨! 나도 알고 있거든? 이 재수 없는 깡통 녀석아!","JPN":"もう！　私だってわかってるよ！　このいけ好かないボロ缶！","ENG":"Oh, shut up! I know it too, you smug Tin Can!","TWN":"可惡！我也知道的好嗎？你這個倒楣的鐵桶！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그래도 할말은 꼭 해야겠어!","JPN":"でもこれだけは言わせてもらうわ！","ENG":"But I've got to say this, no matter what.","TWN":"即便如此，該說的話還是要說！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"잘 들어. 나는 너희 테라브레인을 신뢰하지 않아.","JPN":"いい？　私はあんたたちテラブレインなんて信用していない。","ENG":"Listen up. I don't trust Terrabrains including you.","TWN":"聽好了，我不信任你們這些特拉大腦。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"하지만 그럼에도 이번 계획에 협조하는 이유는 하나뿐이야.","JPN":"それでも今回の計画に協力する理由はたった1つ。","ENG":"Even so, there's only one reason I'm going along with this plan.","TWN":"但是即便如此，我協助這次計畫的理由只有一個。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"전대장님이 계셨다면, 결국 같은 선택을 하셨을 테니까.","JPN":"戦隊長がいたら、結局同じ選択をしたはずだからよ。","ENG":"If Commander were here... she'd make the same choice.","TWN":"如果隊長在的話，最後也會做出同樣的選擇。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"모두를 구하기 위해 기꺼이 우주로 향한 그분이라면, 모른 척하지 않으실 테니까.","JPN":"みんなを助けるために進んで宇宙に出向いたあの人なら、見て見ぬふりなんて絶対しないだろうから。","ENG":"Someone who willingly went into space to save everyone wouldn't just look away.","TWN":"為了拯救所有人而毅然奔向宇宙的他，絕不會置之不理的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"그러니까 착각하지 말라고, 건방진 깡통아.","JPN":"だから勘違いしないでよね、生意気なボロ缶。","ENG":"So don't get the wrong idea, you arrogant Tin Can.","TWN":"所以說別搞錯了，囂張的鐵桶。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"나는 널 돕는 게 아니야. 그분처럼 내가 할 수 있는 일을 할 뿐이야……!","JPN":"私はあんたを手伝っているわけじゃない。あの人のように、私にできることをしているだけだわ……！","ENG":"I'm not here to help you. I'm just doing what I can, just like she would have...!","TWN":"我不是在幫你。我只是在做我能做的事……就像他……！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"후후, 자네의 마음은 잘 알고 있다네.","JPN":"ふふ、君の気持ちは重々承知しているさ。","ENG":"Haha... I understand how you feel.","TWN":"呵呵，我很了解你的心思。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"그리고 너무 걱정하지 말게, 닥터.","JPN":"それからあまり心配することはない、ドクター。","ENG":"And don't worry too much, Doctor.","TWN":"而且不要太擔心，博士。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"자네가 앨리스 전대장의 유지를 잇기로 결정했듯이.","JPN":"君がアリス戦隊長の遺志を継ぐことを決心したように、","ENG":"Just as you chose to carry on Commander Alice's will...","TWN":"就像你決定繼承艾莉絲戰隊長的遺志一樣。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SYSOP_MAIN_NPC_NULL","text":{"KOREA":"나 또한 아버지를 위해, 평의회가 준비할 수 있는 최선의 수를 연산해 두었으니까.","JPN":"私もまた、父のために評議会が用意できる最善の手を演算しておいたのさ。","ENG":"I've run every calculation the Council could manage, for my Father's sake.","TWN":"我也為父親準備了議會能準備的最好的策略。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_MAIN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOCTOR_MAIN_NPC_NULL","text":{"KOREA":"최선이라…….","JPN":"最善ね……","ENG":"Every calculation, huh?","TWN":"盡力而為……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_MAIN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"며칠 뒤","JPN":"数日後","ENG":"A few days later","TWN":"幾天後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 ~ 로터스 관리 경계 구역\\n<color=#ffd34c>CSE LV.2</color>","JPN":"シャレード～ロータス管理警戒区域\\n<color=#ffd34c>CSE LV.2</color>","ENG":"Charade-Lotus Perimeter Zone\\n<color=#ffd34c>CSE Lv. 2</color>","TWN":"查雷德 ~ 洛德斯管理警戒區域\\n<color=#ffd34c>CSELV.2</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はぁ……","ENG":"*Sigh...*","TWN":"哈……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"리하르트가 죽은 지 얼마 지나지도 않았는데, 또 이런 불미스러운 일이 발생하다니.","JPN":"リヒャルトが死んで間もないのに、またこのような不始末なことが起こるとは。","ENG":"Richard's death wasn't that long ago, and now we've got another incident on our hands.","TWN":"理查剛死沒多久，又發生了這種不幸的事。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"로터스에 있다던, 최고 관리자는 갑자기 북방합의체의 영토에 갔다고 하질 않나…….","JPN":"ロータスにいるらしい最高管理者は突然、北方合意体の領土に行ったというし……","ENG":"The Supreme Administrator, who was supposed to be in Lotus, suddenly ran off to the Northern Union territory...","TWN":"在洛德斯的最高管理員突然去了北方和議會的領土……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"함께 공조해야 할 의무가 있는 그 히키코모리 시니어는 연락 두절에…….","JPN":"協力する義務があるあの引きこもりのシニアは音信不通……","ENG":"That hermit Senior who's supposed to be working with us is unreachable...","TWN":"那個有義務一起合作的宅男Senior失聯了……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이런 공상 과학스러운 일이라면, 사족을 못쓰는 시니어 잭슨은 또 실종 상태…….","JPN":"このような空想科学の類には目がないシニア・ジャクソンは、またもや失踪……","ENG":"And Senior Jackson, who usually jumps at this kind of sci-fi nonsense, is conveniently missing...","TWN":"已經是這種科幻般的事情，然後迷戀這些的傑森Senior失蹤了……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"결국, 샤레이드 권한 대행일 뿐인 내가 모든 걸 책임지게 생겼잖아……!","JPN":"結局、シャレードの権限代行に過ぎない私に、全責任が回ってくることに……！","ENG":"Now it's all falling on me, the acting head of Charade...!","TWN":"結果，最後還是由我這個查雷德的許可權代理人來負責一切……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"으으! 아무튼 이게 다 최고 관리자 때문이야!","JPN":"くっ！　これも全部最高管理者のせいだ！","ENG":"Argh! This is all the Supreme Administrator's fault!","TWN":"嗚嗚！反正這都是最高管理者的錯！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"어디 두고 보자고! 이번 일이 끝나면, 철저히 추궁해 줄 테니까!","JPN":"覚えていろ！　今回の件が片付く次第、あらいざらい言わせてやるんだからな！","ENG":"Just wait! Once this is over, I will get some answers!","TWN":"走著瞧吧！這件事結束後，我會徹底追究的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"시니어 님, 지시하신 정찰조 2개 소대 배치 완료되었습니다.","JPN":"シニア、ご指示どおり偵察班2個小隊の配置が完了しました。","ENG":"Two scout squads have been positioned as instructed, ma'am.","TWN":"長官，你指示的兩個偵察小隊已經部署完畢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L16_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"명령만 주시면, 언제든 작전 투입 가능합니다.","JPN":"いつでも作戦に投入可能です。","ENG":"We're ready to move in on your command.","TWN":"只要下達命令，隨時可以投入作戰。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"좋아, 모두 잘 듣도록.","JPN":"よし、総員、よく聞け。","ENG":"Good. Listen up, everyone.","TWN":"好的，大家都聽好了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이번 작전은 관리 경계 구역 상공에 출몰한 미확인 비행체에 대한 정찰 및 조사.","JPN":"今回の作戦は管理警戒区域の上空に出現した未確認飛行物体の偵察及び調査。","ENG":"This operation is a recon and intel-gathering mission targeting the unidentified aircraft that appeared over the perimeter zone.","TWN":"此次作戰是對管理警戒區域上空出現的不明飛行物進行偵察和調查。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"작전 구역을 수색하면서, 비행체에 관한 정보를 최대한 수집하는 것이다.","JPN":"作戦区域を捜索し、飛行物体の情報を最大限収集することを目標とする。","ENG":"Sweep the area and collect as much data as possible on the aircraft.","TWN":"在搜索作戰區域的同時，盡可能收集有關飛行器的資訊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"현재 비행체는 출몰한지 70시간째, 부유하고 있을 뿐 어떠한 움직임도 보이지 않고 있다.","JPN":"現在、飛行物体は出現して70時間が過ぎているが、浮遊しているだけでいかなる動きも見せていない。","ENG":"It's been 70 hours since it showed up, and it hasn't made a single move by just floating there.","TWN":"目前飛行器已經出現了70小時，只是漂浮著，沒有任何動靜。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이에 따라, 잠정적으로 미확인 비행체의 공격성은 낮다고 판단.","JPN":"このことから、暫定的に未確認飛行物体の攻撃性は低いと判断する。","ENG":"Based on that, we're assuming it's not hostile... at least for now.","TWN":"因此，暫時判斷不明飛行物的攻擊性較低。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최대한 조심스럽게 비행체에 접근하되, 만약 특이사항이 발생하면 즉시 보고한다.","JPN":"最大限の注意を払い飛行物体に接近し、異常が発生した場合、即座に報告するように。","ENG":"Approach with extreme caution, and report any unusual activity immediately.","TWN":"儘量小心地接近飛行器，如果發生異常情況，立即報告。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"어쩌면 이건 인류가 지금껏 경험한 적 없었던, 초유의 사태일지도 모른다.","JPN":"もしかするとこれは、人類が未だかつて経験したことのない、未曽有の事態の可能性がある。","ENG":"This could be a crisis unlike anything humanity has ever encountered.","TWN":"或許這是人類至今從未經歷過的，史無前例的事態。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"어떤 일이 발생할지 모르니, 신중하게 대응하도록!","JPN":"どのようなことが起こるかわからない。慎重に対応せよ！","ENG":"We don't know what could happen, so stay sharp and proceed with caution.","TWN":"不知道會發生什麼事，請謹慎應對！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"네, 알겠습니다!","JPN":"はい、了解であります！","ENG":"Understood!","TWN":"好的，知道了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L31_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"정찰조 2개 소대 작전을 시작한다!","JPN":"偵察班2個小隊、作戦を開始する！","ENG":"Scout squads, Alpha and Bravo, begin your operation!","TWN":"偵察隊兩個小隊開始行動！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"여기는 알파.","JPN":"こちらアルファ。","ENG":"This is Alpha.","TWN":"這裡是阿爾法。"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"미확인 비행체가 떠 있는 지점 바로 아래까지 도착했다.","JPN":"未確認飛行物体の浮遊地点の真下に到着した。","ENG":"We've reached the area directly beneath the unidentified aircraft.","TWN":"已經到達了不明飛行物懸停的地點正下方。"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"상황은 이상 무. 침식파 계수는…… ","JPN":"状況は異常なし。侵食波係数は……","ENG":"All clear so far. As for the Corruption ray level...","TWN":"情況一切正常，侵蝕波計數是……"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"알파, 왜 그러지?","JPN":"アルファ、どうした。","ENG":"Alpha, is something wrong?","TWN":"阿爾法，怎麼了？"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L42_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"베타, 작전구역은 틀림없이 CSE LV.2의 침식지대 아니었나?","JPN":"ベータ、作戦区域はCSE LV.2の侵食地帯で間違いないな？","ENG":"Bravo, wasn't this area classified as a CSE Lv. 2 Corrupted Area?","TWN":"貝塔，作戰區域不是CSELV.2的侵蝕地帶嗎？"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"이유는 모르겠지만, 비행체 중심에 가까워질수록 침식파의 강도가 약해지고 있다.","JPN":"理由はわからないが、飛行物体の中心に近づくほど侵食波の強度が弱まっている。","ENG":"I don't know why, but the closer we get to the center of the aircraft, the weaker the Corruption ray is becoming.","TWN":"雖然不知道原因，但越接近飛行體中心，侵蝕波的強度就越弱。"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"무슨 소리야?","JPN":"どういうことだ？","ENG":"What are you saying?","TWN":"什麼聲音？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그럼, 저 우주선이 침식파를 정화하기라도 한다는 뜻이야?","JPN":"つまり、あの宇宙船が侵食波を浄化でもしているというのか？","ENG":"Are you suggesting... that spaceship is purifying the Corruption ray?","TWN":"那麼，那艘太空船是要淨化侵蝕波的意思嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"그건……","JPN":"それは……","ENG":"That's...","TWN":"那個……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L1_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"으아아아아아악!!","JPN":"うわああああああ！！","ENG":"AHHHHHHHHH!","TWN":"呃啊啊啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BATTLEFIELD"},{"id":"L2_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"도, 도망쳐!! 모두 후퇴한다!","JPN":"に、逃げろ！！　総員、撤退する！","ENG":"R-run for it!! Full retreat!","TWN":"快、快逃！！全員撤退！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"알파! 무슨 일이지, 알파!","JPN":"アルファ！　応答せよ、アルファ！","ENG":"Alpha, what's going on?! Alpha, respond!","TWN":"阿爾法！發生什麼事了，阿爾法！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"모두 경계 태세! 알파팀이 당했다!","JPN":"総員、警戒態勢！　チームアルファがやられた！","ENG":"Everyone, stay on high alert! Team Alpha's been hit!","TWN":"全員戒備！阿爾法小隊遭襲了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"당장, 시니어님께…….","JPN":"ただちにシニアに……","ENG":"Someone, get a message to the Senior...","TWN":"立刻——去找Senior……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"분대장님! 전방에서 차원도약 신호가 잡히고 있습니다!","JPN":"分隊長！　前方から次元跳躍の信号を捉えました！","ENG":"Commander! We're detecting a dimension jump signal in front.","TWN":"分隊長！前方捕捉到次元跳躍訊號！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"식별 신호는…… 관리국입니다!","JPN":"識別信号は……管理局です！","ENG":"The identification signal... it's from the Administration!","TWN":"識別訊號是……管理局的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"관리국에서 차원 도약? 무슨 헛소리야? 이 작전은 소규모 정찰 작전이다!","JPN":"管理局が次元跳躍？　何を訳のわからないことを言っている？　この作戦は小規模の偵察作戦だぞ！","ENG":"A dimensional jump from the Administration? That's impossible! This was supposed to be a small-scale recon operation!","TWN":"管理局進行次元跳躍？開什麼玩笑？這次行動是小規模偵察行動！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"우린 차원 함선 같은 거 부른 적 없다고!","JPN":"我々は次元艦船など要請していない！","ENG":"We never called in a dimensional ship!","TWN":"我們從沒召喚過什麼次元艦船！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>유기체 감지. 바이탈 체크 실행.</color>","JPN":"<color=#ff3636>有機体感知。バイタルチェック実行。</color>","ENG":"<color=#ff3636>Organic beings detected. Checking vital signs.</color>","TWN":"<color=#ff3636>有機體檢測，執行生命體征檢查。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_26"},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"뭐, 뭐야… 저건……?","JPN":"な、何だ、あれは……？","ENG":"W-what is... that...?","TWN":"什，什麼…這是……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>바이탈 체크 완료. 침식 증후군 증상 확인 불가.</color>","JPN":"<color=#ff3636>バイタルチェック完了。侵食症候群の症状確認不可。</color>","ENG":"<color=#ff3636>Vital signs checked. Unable to verify Corruption Syndrome symptoms.</color>","TWN":"<color=#ff3636>生命體征檢查完畢，未發現侵蝕綜合症症狀。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L21_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>침식 위험성. 확인 불가.</color>","JPN":"<color=#ff3636>侵食危険性。確認不可。</color>","ENG":"<color=#ff3636>The chances of Corruption. Unable to verify.</color>","TWN":"<color=#ff3636>侵蝕風險！無法確認！</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L22_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>적성 개체를 섬멸합니다.</color>","JPN":"<color=#ff3636>敵性個体を殲滅します。</color>","ENG":"<color=#ff3636>Eliminating hostile entity.</color>","TWN":"<color=#ff3636>殲滅敵方個體。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_27"},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"온다! 모두 대형을 벌려!","JPN":"来るぞ！　総員、隊形を展開！","ENG":"Incoming! All units, spread out!","TWN":"來了！大家展開隊形！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L29_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_QM","text":{"KOREA":"소용없어. 모더레이터는 카운터의 CRF가 아니면 저지하기 힘들거든.","JPN":"無駄だよ。モデレーターはカウンターのCRFじゃなきゃ阻止が難しいの。","ENG":"It's no use. Moderators are tough to stop unless you've got Counters' CRF.","TWN":"沒用的，仲裁者如果不是制裁者的CRF的話，是很難阻止的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_QM","text":{"KOREA":"그러니까 다들 머리 좀 숙여줄래?","JPN":"だからみんな。頭を下げてくれる？","ENG":"So how about you all duck and let us handle this.","TWN":"所以大家能低下頭嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"다, 당신들은……?","JPN":"あ、あなたたちは……？","ENG":"Y-you are...?","TWN":"你、你們是……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>손상 부위 수리 중. 교전 속행 가능.</color>","JPN":"<color=#ff3636>損傷部位を修理中。交戦続行可能。</color>","ENG":"<color=#ff3636>Repairing damage. Ready to engage.</color>","TWN":"<color=#ff3636>正在維修損壞部位，可以繼續交戰。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>새로운 유기체 감지. 바이탈 체크 실행.</color>","JPN":"<color=#ff3636>新しい有機体感知。バイタルチェック実行。</color>","ENG":"<color=#ff3636>New organic beings detected. Checking vital signs.</color>","TWN":"<color=#ff3636>發現新有機體，執行生命確認。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"예고르, 이 딱정벌레 녀석들을 다시 보게 된 게 20년 만인가?","JPN":"イェゴール、このカブトムシどもと相まみえるのって、20年ぶりかしら？","ENG":"Yegor, has it really been 20 years since we last saw these beetles?","TWN":"伊高爾，時隔20年再次見到這些甲蟲了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L39_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"연수로 따지면 그렇습니다, 부전대장님.","JPN":"実際の年月で数えればそのとおりです、副戦隊長。","ENG":"That would be accurate, Deputy Commander.","TWN":"從資歷上來說是這樣的，副隊長。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"뭐, 저희는 그 대부분의 시간을 시공간 동결 상태로 보내긴 했지만요.","JPN":"まあ、我々はそのほとんどの時間を時空間凍結状態で過ごしましたが。","ENG":"Though technically, most of that time we were frozen in temporal suspension.","TWN":"嗯，我們大部分時間都是在時空凍結狀態下度過的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"후후, 그러게.","JPN":"ふふ、そうだね。","ENG":"Haha, that's right.","TWN":"呵呵，是啊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"뭐, 시대가 변하긴 했지만, 그래도 딱정벌레 사냥법까지 잊어버리지는 않았겠지?","JPN":"まあ、時代は変わっちゃったけど、カブトムシの狩り方まで忘れてはいないよね？","ENG":"Sure, times have changed... but you haven't forgotten how to hunt beetles, right?","TWN":"雖然時代變了，但我可沒忘記捕獵甲蟲的方法吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"물론입니다.","JPN":"もちろんです。","ENG":"Of course not.","TWN":"當然了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"에스타크 10문, 장거리 포격 개시!","JPN":"エスターク10門、長距離砲撃開始！","ENG":"Commence bombardment of the ten Estaque cannons!","TWN":"艾斯塔克10門，開始遠端炮擊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>능동방어체계 활성화. 에너지 공명 실드 전개.</color>","JPN":"<color=#ff3636>能動防御体系活性化。エネルギー共鳴シールド展開。</color>","ENG":"<color=#ff3636>Activating active defense system. Deploying energy resonance shield.</color>","TWN":"<color=#ff3636>主動防禦系統啟動。能量共鳴護盾展開。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_27"},{"id":"L1_1","type":"dialog","speaker":"MODER_BOSS_NULL_NULL","text":{"KOREA":"<color=#ff3636>섬멸 태세로 변경. 기갑 병기를 우선 제거합니다.</color>","JPN":"<color=#ff3636>殲滅態勢に変更。機甲兵器を優先除去します。</color>","ENG":"<color=#ff3636>Switching to Elimination mode. Prioritizing armored vehicles.</color>","TWN":"<color=#ff3636>切換為殲滅態勢，優先消滅機甲兵器。</color>"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L4_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"모더레이터의 공격 대상이 바뀐 지금입니다!","JPN":"モデレーターの攻撃対象が移った今がチャンスです！","ENG":"Now's our chance! The Moderator's switched targets.","TWN":"仲裁者的攻擊目標已經改變了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"가시죠, 부전대장님. 엄호하겠습니다!","JPN":"行きましょう、副戦隊長。援護します！","ENG":"Let's move, Deputy Commander! I'll cover you!","TWN":"走吧，副隊長，我會掩護你的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"좋아, 그럼 부탁할게. 예고르.","JPN":"よし、それじゃあ頼むね、イェゴール。","ENG":"All right then. I'm counting on you, Yegor.","TWN":"好，那就拜託你了，伊高爾。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"알렉스, 미리 말해두지만 너무 무리하지는 마세요.","JPN":"アレックス、先に言っておきますが、あまり無理はしないでください。","ENG":"Alex, just a heads-up. Don't push yourself too hard.","TWN":"雅蕾克絲，提前告訴你，不要太勉強自己。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무리 슈트로 보조한다고 하더라도, 당신의 재생 시술은 아직 완벽하지 않으니까요.","JPN":"いくらスーツの補助を受けているとはいえ、あなたの再生施術はまだ完璧ではありません。","ENG":"Even with the suit assisting you, your regeneration procedure isn't fully reliable yet.","TWN":"即使有戰鬥服輔助，你的再生手術仍然不完美。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"10분…….","JPN":"10分……","ENG":"10 minutes...","TWN":"10分鐘……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우선은 그 정도가 당신의 활동 한계라고 생각하고 움직이세요.","JPN":"とりあえずはそれがあなたの活動限界と思って行動してください。","ENG":"For now, assume that's your upper limit and act accordingly.","TWN":"首先，請以這個程度作為你的活動極限來行動。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"10분이라… 원래 뭐든, 질질 끌면 재미없는 법이지.","JPN":"10分か……何事もずるずると長引かせるとつまらないもんね。","ENG":"Ten minutes, huh? Well, dragging things out is never fun anyway.","TWN":"10分鐘嗎……本來什麼事都一樣，拖拖拉拉就沒意思了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"걱정하지 마. 부사장님.","JPN":"心配しないで、副社長。","ENG":"Don't worry, Vice President.","TWN":"不用擔心，副總。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"오늘 전장은 재활 운동 겸, 새로운 장비의 프로모션이니까.","JPN":"今日の戦場はリハビリ兼新装備のプロモーションだから。","ENG":"Today's battlefield is part rehab, part field test for the new gear.","TWN":"今天的戰場既是康復訓練，也是新裝備的推廣。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_ADMIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};